# enterprise_portal/auth_backend.py
from django.contrib.auth.backends import ModelBackend
from django.contrib.auth import get_user_model

User = get_user_model()

class SAMLBackend(ModelBackend):
    def authenticate(self, request, saml_name_id=None, saml_attributes=None, **kwargs):
        if not saml_name_id:
            return None

        user = None
        username = saml_attributes.get("username") if saml_attributes else None
        email = saml_attributes.get("email") if saml_attributes else None

        if username:
            try:
                user = User.objects.get(username=username)
            except User.DoesNotExist:
                user = None

        if not user and email:
            try:
                user = User.objects.get(email=email)
            except User.DoesNotExist:
                user = None

        if not user:
            try:
                user = User.objects.get(username=saml_name_id)
            except User.DoesNotExist:
                user = None

        return user

# enterprise_portal/saml.py
import base64
from dataclasses import dataclass
from typing import Dict, List, Optional
from xml.etree import ElementTree as ET
from django.conf import settings

SAML_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol"
SAML_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion"
NS = {
    "samlp": SAML_PROTOCOL_NS,
    "saml": SAML_ASSERTION_NS,
}

class SAMLValidationError(Exception):
    pass

@dataclass
class SAMLPrincipal:
    name_id: str
    attributes: Dict[str, str]
    issuer: Optional[str]
    audience: Optional[str]

def decode_saml_response(saml_response_b64: str) -> str:
    try:
        return base64.b64decode(saml_response_b64).decode("utf-8")
    except Exception as exc:
        raise SAMLValidationError("Invalid SAMLResponse encoding") from exc

def parse_saml_response(xml_data: str) -> SAMLPrincipal:
    try:
        root = ET.fromstring(xml_data)
    except ET.ParseError as exc:
        raise SAMLValidationError("Malformed XML in SAMLResponse") from exc

    validate_basic_structure(root)

    issuer = _find_text(root, ".//saml:Issuer")
    assertion = root.find(".//saml:Assertion", NS)
    if assertion is None:
        raise SAMLValidationError("Missing Assertion")

    subject_name_id = _find_text(assertion, ".//saml:Subject/saml:NameID")
    if not subject_name_id:
        raise SAMLValidationError("Missing Subject NameID")

    audience = _find_text(assertion, ".//saml:Conditions/saml:AudienceRestriction/saml:Audience")
    attributes = extract_attributes(assertion)

    mapped = map_attributes(attributes)

    return SAMLPrincipal(
        name_id=subject_name_id,
        attributes=mapped,
        issuer=issuer,
        audience=audience,
    )

def validate_basic_structure(root: ET.Element) -> None:
    response_tag = _strip_ns(root.tag)
    if response_tag != "Response":
        raise SAMLValidationError("Root element must be Response")

    status_code = root.find(".//samlp:Status/samlp:StatusCode", NS)
    if status_code is None:
        raise SAMLValidationError("Missing StatusCode")

    assertion = root.find(".//saml:Assertion", NS)
    if assertion is None:
        raise SAMLValidationError("Missing Assertion element")

    subject = assertion.find(".//saml:Subject", NS)
    if subject is None:
        raise SAMLValidationError("Missing Subject element")

def extract_attributes(assertion: ET.Element) -> Dict[str, List[str]]:
    results: Dict[str, List[str]] = {}

    for attr in assertion.findall(".//saml:AttributeStatement/saml:Attribute", NS):
        name = attr.attrib.get("Name") or attr.attrib.get("FriendlyName")
        if not name:
            continue

        values = []
        for value in attr.findall("./saml:AttributeValue", NS):
            if value.text is not None:
                values.append(value.text.strip())

        if values:
            results[name] = values

    return results

def map_attributes(raw_attributes: Dict[str, List[str]]) -> Dict[str, str]:
    mapped = {}
    attribute_map = settings.SAML_SP.get("ATTRIBUTE_MAP", {})

    for target, aliases in attribute_map.items():
        for alias in aliases:
            if alias in raw_attributes and raw_attributes[alias]:
                mapped[target] = raw_attributes[alias][0]
                break

    for key, values in raw_attributes.items():
        if key not in mapped and values:
            mapped[key] = values[0]

    return mapped

def _find_text(root: ET.Element, path: str) -> Optional[str]:
    node = root.find(path, NS)
    if node is None or node.text is None:
        return None
    return node.text.strip()

def _strip_ns(tag: str) -> str:
    if "}" in tag:
        return tag.split("}", 1)[1]
    return tag

# enterprise_portal/views.py
from django.conf import settings
from django.contrib import messages
from django.contrib.auth import get_user_model, login, logout
from django.http import HttpRequest, HttpResponse, HttpResponseBadRequest
from django.shortcuts import redirect
from django.views.decorators.csrf import csrf_exempt
from .saml import SAMLValidationError, decode_saml_response, parse_saml_response

User = get_user_model()

@csrf_exempt
def saml_acs_view(request: HttpRequest) -> HttpResponse:
    if request.method != "POST":
        return HttpResponseBadRequest("Only POST allowed")

    saml_response = request.POST.get("SAMLResponse")
    if not saml_response:
        return HttpResponseBadRequest("Missing SAMLResponse")

    try:
        xml_data = decode_saml_response(saml_response)
        principal = parse_saml_response(xml_data)
        validate_business_rules(principal)
        user = get_or_create_user(principal)
        user.backend = "django.contrib.auth.backends.ModelBackend"
        login(request, user)
        request.session["saml_name_id"] = principal.name_id
        request.session["saml_attributes"] = principal.attributes
        return redirect(settings.LOGIN_REDIRECT_URL)
    except SAMLValidationError as exc:
        return HttpResponseBadRequest(f"SAML validation failed: {exc}")

def validate_business_rules(principal) -> None:
    expected_issuer = settings.SAML_SP.get("IDP_ENTITY_ID")
    if expected_issuer and principal.issuer != expected_issuer:
        raise SAMLValidationError("Unexpected issuer")

    expected_audience = settings.SAML_SP.get("AUDIENCE")
    if expected_audience and principal.audience and principal.audience != expected_audience:
        raise SAMLValidationError("Unexpected audience")

def get_or_create_user(principal):
    attrs = principal.attributes
    username = attrs.get("username") or attrs.get("email") or principal.name_id

    user = None
    try:
        user = User.objects.get(username=username)
    except User.DoesNotExist:
        email = attrs.get("email")
        if email:
            try:
                user = User.objects.get(email=email)
            except User.DoesNotExist:
                user = None

    if not user:
        if not settings.SAML_SP.get("CREATE_UNKNOWN_USERS", True):
            raise SAMLValidationError("User does not exist")
        user = User.objects.create_user(
            username=username[:150],
            email=attrs.get("email", "")[:254],
            first_name=attrs.get("first_name", "")[:150],
            last_name=attrs.get("last_name", "")[:150],
        )
        user.set_unusable_password()
        user.save()

    if settings.SAML_SP.get("UPDATE_USER_FIELDS", True):
        updated = False
        for field in ["email", "first_name", "last_name"]:
            value = attrs.get(field)
            if value is not None and getattr(user, field) != value:
                setattr(user, field, value)
                updated = True
        if updated:
            user.save()

    return user

def home_view(request: HttpRequest) -> HttpResponse:
    if request.user.is_authenticated:
        attrs = request.session.get("saml_attributes", {})
        body = [
            f"Authenticated as: {request.user.username}",
            f"NameID: {request.session.get('saml_name_id', '')}",
            f"Attributes: {attrs}",
            '<br><a href="/logout/">Logout</a>',
        ]
    else:
        body = [
            "Not authenticated",
            "<br>POST a SAMLResponse to /saml/acs/",
        ]
    return HttpResponse("<br>".join(body))

def logout_view(request: HttpRequest) -> HttpResponse:
    logout(request)
    messages.info(request, "Logged out")
    return redirect(settings.LOGOUT_REDIRECT_URL)

