# enterprise_portal/tests.py
import base64
from django.test import TestCase, Client
from django.contrib.auth import get_user_model

User = get_user_model()

VALID_SAML = """
<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">
  <saml:Issuer>test-idp</saml:Issuer>
  <samlp:Status>
    <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
  </samlp:Status>
  <saml:Assertion>
    <saml:Subject>
      <saml:NameID>john.doe</saml:NameID>
    </saml:Subject>
    <saml:Conditions>
      <saml:AudienceRestriction>
        <saml:Audience>django-enterprise-portal</saml:Audience>
      </saml:AudienceRestriction>
    </saml:Conditions>
    <saml:AttributeStatement>
      <saml:Attribute Name="email">
        <saml:AttributeValue>john@example.com</saml:AttributeValue>
      </saml:Attribute>
      <saml:Attribute Name="first_name">
        <saml:AttributeValue>John</saml:AttributeValue>
      </saml:Attribute>
      <saml:Attribute Name="last_name">
        <saml:AttributeValue>Doe</saml:AttributeValue>
      </saml:Attribute>
    </saml:AttributeStatement>
  </saml:Assertion>
</samlp:Response>
""".strip()

class SAMLACSTests(TestCase):
    def setUp(self):
        self.client = Client()

    def test_saml_login_creates_user(self):
        response = self.client.post("/saml/acs/", {"SAMLResponse": base64.b64encode(VALID_SAML.encode()).decode()})
        self.assertEqual(response.status_code, 302)
        self.assertTrue(User.objects.filter(username="john@example.com").exists())

    def test_reject_invalid_xml(self):
        bad = base64.b64encode(b"<bad>").decode()
        response = self.client.post("/saml/acs/", {"SAMLResponse": bad})
        self.assertEqual(response.status_code, 400)

